import{_ as e,o as i,c as t,a0 as l}from"./chunks/framework.RL10UjUE.js";const u=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md"}'),r={name:"guide/faq.md"};function h(o,a,s,d,n,c){return i(),t("div",null,[...a[0]||(a[0]=[l(`<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><h2 id="一般" tabindex="-1">一般 <a class="header-anchor" href="#一般" aria-label="Permalink to &quot;一般&quot;">​</a></h2><h3 id="ブックマークデータはどこに保存されますか" tabindex="-1">ブックマークデータはどこに保存されますか？ <a class="header-anchor" href="#ブックマークデータはどこに保存されますか" aria-label="Permalink to &quot;ブックマークデータはどこに保存されますか？&quot;">​</a></h3><p>ローカルの SQLite データベース（<code>userData/bookmarks.db</code>）に保存されます。詳細はセットアップガイドの「データの保存場所」を参照してください。</p><h3 id="データベースを手動でバックアップしたい" tabindex="-1">データベースを手動でバックアップしたい <a class="header-anchor" href="#データベースを手動でバックアップしたい" aria-label="Permalink to &quot;データベースを手動でバックアップしたい&quot;">​</a></h3><p>データベースファイル（<code>bookmarks.db</code>）を直接コピーしてください。アプリが起動していない状態で行うことを推奨します。</p><h2 id="同期について" tabindex="-1">同期について <a class="header-anchor" href="#同期について" aria-label="Permalink to &quot;同期について&quot;">​</a></h2><h3 id="同期データは-github-に公開されますか" tabindex="-1">同期データは GitHub に公開されますか？ <a class="header-anchor" href="#同期データは-github-に公開されますか" aria-label="Permalink to &quot;同期データは GitHub に公開されますか？&quot;">​</a></h3><p>リポジトリを <strong>非公開</strong> で作成すれば、あなた以外はアクセスできません。公開リポジトリでも構いませんが、ブックマークのURLが公開されることに留意してください。</p><h3 id="pat-の権限は最小限で済みますか" tabindex="-1">PAT の権限は最小限で済みますか？ <a class="header-anchor" href="#pat-の権限は最小限で済みますか" aria-label="Permalink to &quot;PAT の権限は最小限で済みますか？&quot;">​</a></h3><p><code>repo</code> スコープが必要です（コンテンツの読み書きのため）。トークンはアプリのローカル設定にのみ保存され、GitHub には送信されません（API 経由の認証のみに使用）。</p><h3 id="複数デバイスで同時に同期したらどうなりますか" tabindex="-1">複数デバイスで同時に同期したらどうなりますか？ <a class="header-anchor" href="#複数デバイスで同時に同期したらどうなりますか" aria-label="Permalink to &quot;複数デバイスで同時に同期したらどうなりますか？&quot;">​</a></h3><p>各デバイスが独立したファイルに保存されるため、同時同期でも問題ありません。同じブックマークが別々に更新された場合のみ、次回同期時にコンフリクトが検出されます。</p><h3 id="デバイスを削除したい" tabindex="-1">デバイスを削除したい <a class="header-anchor" href="#デバイスを削除したい" aria-label="Permalink to &quot;デバイスを削除したい&quot;">​</a></h3><p>該当デバイスの <code>device-{id}.json</code> をリポジトリから削除し、<code>metadata/devices.json</code> から該当エントリを削除してください。</p><h2 id="インポートについて" tabindex="-1">インポートについて <a class="header-anchor" href="#インポートについて" aria-label="Permalink to &quot;インポートについて&quot;">​</a></h2><h3 id="インポート後にブラウザのブックマークは変更されますか" tabindex="-1">インポート後にブラウザのブックマークは変更されますか？ <a class="header-anchor" href="#インポート後にブラウザのブックマークは変更されますか" aria-label="Permalink to &quot;インポート後にブラウザのブックマークは変更されますか？&quot;">​</a></h3><p>いいえ。本ツールはブラウザのデータを「読み取り」しません。ブラウザからエクスポートした HTML ファイルを取り込む形のため、ブラウザ側のデータに影響はありません。</p><h3 id="フォルダ構造は保持されますか" tabindex="-1">フォルダ構造は保持されますか？ <a class="header-anchor" href="#フォルダ構造は保持されますか" aria-label="Permalink to &quot;フォルダ構造は保持されますか？&quot;">​</a></h3><p>HTML ファイル内のフォルダ構造はタグとしてインポートされます。ツール内ではフラットな一覧として管理されます。</p><h2 id="トラブルシューティング" tabindex="-1">トラブルシューティング <a class="header-anchor" href="#トラブルシューティング" aria-label="Permalink to &quot;トラブルシューティング&quot;">​</a></h2><h3 id="アプリが起動しない" tabindex="-1">アプリが起動しない <a class="header-anchor" href="#アプリが起動しない" aria-label="Permalink to &quot;アプリが起動しない&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rebuild</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # better-sqlite3 を再ビルド</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 再試行</span></span></code></pre></div><h3 id="同期が「接続失敗」になる" tabindex="-1">同期が「接続失敗」になる <a class="header-anchor" href="#同期が「接続失敗」になる" aria-label="Permalink to &quot;同期が「接続失敗」になる&quot;">​</a></h3><ul><li>GitHub のトークンが有効か確認（トークンの有効期限が切れていないか）</li><li>リポジトリ名・所有者が正しいか確認</li><li>ネットワーク接続を確認</li></ul><h3 id="重複が検出されない" tabindex="-1">重複が検出されない <a class="header-anchor" href="#重複が検出されない" aria-label="Permalink to &quot;重複が検出されない&quot;">​</a></h3><ul><li>URL の正規化後も区別が必要なページの場合、手動で判断してください</li><li>同一ドメインでもクエリパラメータが重要な場合は、正規化ルールの調整を検討してください</li></ul><h3 id="ai-アシスタントが応答しない" tabindex="-1">AI アシスタントが応答しない <a class="header-anchor" href="#ai-アシスタントが応答しない" aria-label="Permalink to &quot;AI アシスタントが応答しない&quot;">​</a></h3><ul><li><code>http://localhost:9876/api/health</code> にアクセスしてサーバが起動しているか確認</li><li>Zed の AI 機能が有効か確認</li><li>ファイアウォールでローカルポートがブロックされていないか確認</li></ul>`,29)])])}const b=e(r,[["render",h]]);export{u as __pageData,b as default};
